kubectl logs es-0 -n elasticsearch --tail=30 2>/dev/null | python3 -c "
import sys, json
for line in sys.stdin:
    try:
        obj = json.loads(line.strip())
        lvl = obj.get('log.level','')
        msg = obj.get('message','')
        err = obj.get('error.message','')
        if lvl in ('ERROR','WARN') or 'transport' in msg.lower() or 'ssl' in msg.lower() or 'discovery' in msg.lower():
            print(f'[{lvl}] {msg}' + (f' | ERR: {err}' if err else ''))
    except:
        print(line.rstrip())
" 2>/dev/null
